type QueryIntent = {tenantId: string; readYourWritesUntil?: number; consistency?: 'strong' | 'eventual'};

export function pickPool(intent: QueryIntent) {
  const needsPrimary = intent.consistency === 'strong' || (intent.readYourWritesUntil ?? 0) > Date.now();
  return needsPrimary ? primaryPool : replicaPool;
}

export async function listOrders(intent: QueryIntent) {
  const pool = pickPool(intent);
  return pool.query('select id, total_cents, created_at from orders where tenant_id = $1 order by created_at desc limit 50', [intent.tenantId]);
}

